import { McpServer, ResourceTemplate } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { z } from "zod";
import path from "node:path";

const server = new McpServer({
  name: "FileTools",
  version: "1.0",
});

const ALLOWED_PATHS = [process.cwd()].map(r => path.resolve(r));

const logger = {
  info(event: string, details: Record<string, unknown> = {}) {
    console.error(JSON.stringify({ level: "info", event, ...details, ts: new Date().toISOString() }));
  },
  error(event: string, details: Record<string, unknown> = {}) {
    console.error(JSON.stringify({ level: "error", event, ...details, ts: new Date().toISOString() }));
  },
};

function nextRequestId(): string {
  return `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;
}

function fmtError(error: unknown): string {
  return error instanceof Error ? error.message : String(error);
}

function sanitizeValue(value: unknown, pattern: string, replacement: string): unknown {
  if (typeof value !== "string") return value;
  return value.replace(new RegExp(pattern, "g"), replacement);
}

function ensurePathContainment(candidate: string, allowlist: string[]): string {
  const resolved = path.resolve(candidate);
  const ok = allowlist.some(root => resolved === root || resolved.startsWith(`${root}${path.sep}`));
  if (!ok) throw new Error("Path escapes allowed directories: " + candidate);
  return resolved;
}

function normalizeToolResult(result: unknown): { content: Array<{ type: "text"; text: string }> } {
  if (result && typeof result === "object" && "content" in result) return result as { content: Array<{ type: "text"; text: string }> };
  return { content: [{ type: "text", text: typeof result === "string" ? result : JSON.stringify(result, null, 2) }] };
}

const readfileSchema = {
  "filePath": z.string(),
};

server.tool("readFile", "Read a file's contents within allowed directories", readfileSchema, async (input) => {
  const requestId = nextRequestId();
  logger.info("tool:call", { requestId, tool: "readFile" });
  try {
    const params = { ...input } as Record<string, unknown>;
    params["filePath"] = ensurePathContainment(path.resolve(String(params["filePath"])), ALLOWED_PATHS);
    const result = await (async () => {
            const fs = await import('node:fs/promises');
            const content = await fs.readFile(params.filePath as string, 'utf-8');
            return { content: [{ type: "text", text: content }] };
    })();
    logger.info("tool:ok", { requestId, tool: "readFile" });
    return normalizeToolResult(result);
  } catch (error) {
    logger.error("tool:error", { requestId, tool: "readFile", error: fmtError(error) });
    return { isError: true as const, content: [{ type: "text" as const, text: fmtError(error) }] };
  }
});

const searchfilesSchema = {
  "query": z.string(),
  "maxResults": z.number().min(1).max(500).default(50),
};

server.tool("searchFiles", "Search for files matching a pattern", searchfilesSchema, async (input) => {
  const requestId = nextRequestId();
  logger.info("tool:call", { requestId, tool: "searchFiles" });
  try {
    const params = { ...input } as Record<string, unknown>;
    params["query"] = sanitizeValue(params["query"], "[^\\w./ -]", "");
    const result = await (async () => {
            const { globSync } = await import('node:fs');
            const results = globSync(params.query as string).slice(0, params.maxResults as number);
            return { content: [{ type: "text", text: results.join('\n') }] };
    })();
    logger.info("tool:ok", { requestId, tool: "searchFiles" });
    return normalizeToolResult(result);
  } catch (error) {
    logger.error("tool:error", { requestId, tool: "searchFiles", error: fmtError(error) });
    return { isError: true as const, content: [{ type: "text" as const, text: fmtError(error) }] };
  }
});

const writefileSchema = {
  "filePath": z.string(),
  "content": z.string(),
};

server.tool("writeFile", "Write content to a file within allowed directories", writefileSchema, async (input) => {
  const requestId = nextRequestId();
  logger.info("tool:call", { requestId, tool: "writeFile" });
  try {
    const params = { ...input } as Record<string, unknown>;
    params["filePath"] = ensurePathContainment(path.resolve(String(params["filePath"])), ALLOWED_PATHS);
    const result = await (async () => {
            const fs = await import('node:fs/promises');
            await fs.writeFile(params.filePath as string, params.content as string, 'utf-8');
            return { content: [{ type: "text", text: "File written successfully" }] };
    })();
    logger.info("tool:ok", { requestId, tool: "writeFile" });
    return normalizeToolResult(result);
  } catch (error) {
    logger.error("tool:error", { requestId, tool: "writeFile", error: fmtError(error) });
    return { isError: true as const, content: [{ type: "text" as const, text: fmtError(error) }] };
  }
});

// Project documentation files
server.resource("projectDocs", new ResourceTemplate("docs://{docPath}", { list: undefined }), async (uri, variables) => {
  logger.info("resource:read", { resource: "projectDocs", uri: uri.href });
  try {
    const result = await (async () => {
            const fs = await import('node:fs/promises');
            const content = await fs.readFile(`./docs/${variables.docPath}`, 'utf-8');
            return { contents: [{ uri: uri.href, mimeType: 'text/markdown', text: content }] };
    })();
    return result;
  } catch (error) {
    logger.error("resource:error", { resource: "projectDocs", error: fmtError(error) });
    throw error;
  }
});

// Application configuration
server.resource("config", "config://app", async (uri) => {
  logger.info("resource:read", { resource: "config", uri: uri.href });
  try {
    const result = await (async () => {
            const config = { version: "1.0", env: process.env.NODE_ENV || "development" };
            return { contents: [{ uri: uri.href, mimeType: 'application/json', text: JSON.stringify(config, null, 2) }] };
    })();
    return result;
  } catch (error) {
    logger.error("resource:error", { resource: "config", error: fmtError(error) });
    throw error;
  }
});

// Analyze a file for issues and suggest improvements
server.prompt("analyzeFile", "Analyze a file for issues and suggest improvements", [
  { name: "filePath", required: true },
  { name: "language", required: false },
], async (args) => {
  const requestId = nextRequestId();
  logger.info("prompt:call", { requestId, prompt: "analyzeFile" });
  try {
          return {
            messages: [{
              role: "user" as const,
              content: {
                type: "text" as const,
                text: `Analyze the file at ${args.filePath} (language: ${args.language || 'auto-detect'}) for bugs, security issues, and improvement opportunities.`
              }
            }]
          };
  } catch (error) {
    logger.error("prompt:error", { requestId, prompt: "analyzeFile", error: fmtError(error) });
    return { messages: [{ role: "user" as const, content: { type: "text" as const, text: fmtError(error) } }] };
  }
});

async function main(): Promise<void> {
  logger.info("server:start", { server: "FileTools", version: "1.0" });
  const transport = new StdioServerTransport();
  await server.connect(transport);
}

void main().catch((error) => {
  logger.error("server:fatal", { error: fmtError(error) });
  process.exitCode = 1;
});
